type Server struct {
    Host string
    Port int
    TLS  bool
}
// &T{}는 할당 후 포인터 반환 ⭐
s := &Server{
    Host: "0.0.0.0",
    Port: 8080,
}
// 자동 역참조: (*s).Host 불필요!
fmt.Println(s.Host) // 0.0.0.0
s.Port = 3000       // 직접 수정
s.TLS = true        // 원본 변경 💡

// Go는 항상 pass by value!
func reset(n int) {
    n = 0 // 복사본만 변경
}
// 포인터 전달 → 원본 수정 가능
func resetPtr(n *int) {
    *n = 0 // 원본 변경 ⭐
}

score := 95
reset(score)
fmt.Println(score)    // 95
resetPtr(&score)
fmt.Println(score)    // 0
// 포인터 자체도 복사되어 전달됨 💡

var p *int // 제로값은 nil
// *p → panic: nil dereference!

// nil guard 패턴 ✅
if p != nil {
    fmt.Println(*p)
}
// 생성자에서 nil 반환 활용 ⭐
func FindUser(id int) *User {
    if id <= 0 {
        return nil // 없음 표현
    }
    return &User{ID: id}
}
