// 포인터 리시버: 상태 변경 ✏️
func (s *Server) SetHost(h string) {
    s.Host = h // 원본 수정
}
// 값 리시버: 읽기 전용 📖
func (s Server) Addr() string {
    return s.Host + ":" + ...
}
// slice·map·chan은 내부 포인터 💡
func fill(s []int) {
    s[0] = 999 // 원본 변경됨
}
